import React, { useEffect, useState } from "react";
import { Trash2, Pencil, Plus, Search } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home"); // home | add
  const [search, setSearch] = useState("");
  const [sort, setSort] = useState("order");
  const [name, setName] = useState("");
  const [order, setOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);

  /* ================= FETCH ================= */
  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();
    const parentLinks = data.filter((l) => !l.parent);
    setLinks(parentLinks);
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* ================= SORT + SEARCH ================= */
  const processedLinks = links
    .filter((l) =>
      l.name.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => {
      if (sort === "name") return a.name.localeCompare(b.name);
      if (sort === "status") return b.isActive - a.isActive;
      return a.order - b.order;
    });

  /* ================= SUBMIT ================= */
  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name,
        order,
        isActive,
        parent: null,
      }),
    });

    setName("");
    setOrder(0);
    setIsActive(true);
    setView("home");
    fetchLinks();
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        
        {/* HEADER */}
        <div className={design.header}>
          <h1 className={design.title}>Parent Navigation Links</h1>
          <p className={design.subtitle}>
            Manage main menu items only.
          </p>

          {/* PATH */}
          <div className={design.pathWrapper}>
            <span
              onClick={() => setView("home")}
              className={design.pathLink}
            >
              linkhome
            </span>

            {view === "add" && (
              <span className={design.pathActive}>
                /add-link
              </span>
            )}
          </div>
        </div>

        {/* NAVBAR */}
        <div className={design.navbar}>
          
          {/* LEFT SIDE */}
          <div className="flex flex-col sm:flex-row gap-3 w-full sm:w-auto">
            <div className={design.searchWrapper}>
              <Search size={16} />
              <input
                type="text"
                placeholder="Search..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className={design.searchInput}
              />
            </div>

            <select
              value={sort}
              onChange={(e) => setSort(e.target.value)}
              className={design.sortSelect}
            >
              <option value="order">Sort by Order</option>
              <option value="name">Sort by Name</option>
              <option value="status">Sort by Status</option>
            </select>
          </div>

          {/* ADD BUTTON */}
          <button
            onClick={() => setView("add")}
            className={design.addButtonDark}
          >
            <Plus size={16} />
            Add Link
          </button>
        </div>

        {/* ================= HOME VIEW ================= */}
        {view === "home" && (
          <div className={design.table}>
            {processedLinks.map((link) => (
              <div key={link._id} className={design.row}>
                <div>{link.name}</div>
                <div>{link.order}</div>
                <div>
                  {link.isActive ? "Active" : "Inactive"}
                </div>
                <div className="flex justify-end gap-4">
                  <Pencil size={16} className="cursor-pointer" />
                  <Trash2 size={16} className="cursor-pointer text-red-500" />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ================= ADD VIEW ================= */}
        <AnimatePresence>
          {view === "add" && (
            <motion.form
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              onSubmit={handleSubmit}
              className={design.form}
            >
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
              />

              <input
                type="number"
                placeholder="Order"
                value={order}
                onChange={(e) => setOrder(Number(e.target.value))}
                className={design.input}
              />

              <select
                value={isActive}
                onChange={(e) => setIsActive(e.target.value === "true")}
                className={design.input}
              >
                <option value="true">Active</option>
                <option value="false">Inactive</option>
              </select>

              <button type="submit" className={design.submitButtonDark}>
                Create Link
              </button>
            </motion.form>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default LinkHome;
